 1	import { ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  Divider,
 4	  TextContent,
 5	  TextVariants,
 6	  Text,
 7	} from '@patternfly/react-core';
 8	import * as React from 'react';
 9	import { useTranslation } from 'react-i18next';
10	import ProjectsList from './ProjectsList';
11	import './AllProjectsPage.scss';
12	
13	interface AllProjectsPageProps {
14	  pageTitle?: string;
15	}
16	
17	const AllProjectsPage: React.FC<AllProjectsPageProps> = ({ pageTitle }) => {
18	  const { t } = useTranslation('plugin__pipelines-console-plugin');
19	  return (
20	    <>
21	      <ListPageHeader title={pageTitle || t('Pipelines')} />
22	      <TextContent className="cp-all-projects-page-description">
23	        <Text component={TextVariants.p}>
24	          {t('Select a Project to view its details')}
25	        </Text>
26	      </TextContent>
27	      <Divider className="co-divider" />
28	      <ProjectsList />
29	    </>
30	  );
31	};
32	
33	export default AllProjectsPage;

